import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"金句 · 按主题","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/index.md","filePath":"05_quotes/by-theme/index.md"}'),c={name:"05_quotes/by-theme/index.md"};function n(h,t,d,s,l,i){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="金句-·-按主题" tabindex="-1">金句 · 按主题 <a class="header-anchor" href="#金句-·-按主题" aria-label="Permalink to &quot;金句 · 按主题&quot;">​</a></h1><blockquote><p>巴菲特70年投资哲学的核心主题分类。</p></blockquote><hr><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>核心金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/intrinsic-value.html">内在价值</a></td><td>&quot;价格是你付出的，价值是你得到的。&quot;</td></tr><tr><td><a href="/02_concepts/safety-margin.html">安全边际</a></td><td>&quot;安全边际是投资的基石。&quot;</td></tr><tr><td><a href="/02_concepts/compounding.html">复利</a></td><td>&quot;复利是神奇的力量，是好生意的标志。&quot;</td></tr><tr><td><a href="/02_concepts/long-term.html">长期主义</a></td><td>&quot;如果你不打算持有一只股票十年，那连持有十分钟都不要考虑。&quot;</td></tr><tr><td><a href="/02_concepts/circle-of-competence.html">能力圈</a></td><td>&quot;知道你不知道什么，比你知道什么更重要。&quot;</td></tr><tr><td><a href="/02_concepts/contrarian.html">逆向思维</a></td><td>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。&quot;</td></tr></tbody></table><h2 id="商业逻辑" tabindex="-1">商业逻辑 <a class="header-anchor" href="#商业逻辑" aria-label="Permalink to &quot;商业逻辑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>核心金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/moat.html">护城河</a></td><td>&quot;经济城堡周围的护城河，是抵御竞争的持久优势。&quot;</td></tr><tr><td><a href="/02_concepts/insurance-float.html">保险浮存金</a></td><td>&quot;浮存金是伯克希尔最重要的低成本资金来源。&quot;</td></tr><tr><td><a href="/02_concepts/capital-allocation.html">资本配置</a></td><td>&quot;资本配置是CEO最重要的职责。&quot;</td></tr><tr><td><a href="/02_concepts/share-buybacks.html">股票回购</a></td><td>&quot;只有在股票远低于内在价值时，回购才有意义。&quot;</td></tr></tbody></table><h2 id="风险与治理" tabindex="-1">风险与治理 <a class="header-anchor" href="#风险与治理" aria-label="Permalink to &quot;风险与治理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主题</th><th>核心金句</th></tr></thead><tbody><tr><td><a href="/02_concepts/risk.html">风险</a></td><td>&quot;风险来自于你不知道自己在做什么。&quot;</td></tr><tr><td><a href="/02_concepts/reputation.html">声誉</a></td><td>&quot;声誉是CEO最宝贵的资产。&quot;</td></tr><tr><td><a href="/02_concepts/management.html">管理层</a></td><td>&quot;找一个比你更聪明、更有品格的人，然后充分授权。&quot;</td></tr><tr><td><a href="/02_concepts/corporate-governance.html">董事会治理</a></td><td>&quot;不要让糟糕的董事会控制你的公司。&quot;</td></tr><tr><td><a href="/02_concepts/executive-compensation.html">高管薪酬</a></td><td>&quot;激励必须与结果挂钩，且简单可衡量。&quot;</td></tr><tr><td><a href="/02_concepts/accounting-earnings.html">GAAP与真实盈利</a></td><td>&quot;会计准则只是商业现实的参考，而非替代。&quot;</td></tr></tbody></table><hr><h2 id="主题页面列表" tabindex="-1">主题页面列表 <a class="header-anchor" href="#主题页面列表" aria-label="Permalink to &quot;主题页面列表&quot;">​</a></h2><p><strong>投资哲学：</strong> <a href="/02_concepts/intrinsic-value.html">内在价值</a> · <a href="/02_concepts/moat.html">护城河</a> · <a href="/02_concepts/safety-margin.html">安全边际</a> · <a href="/02_concepts/compounding.html">复利</a> · <a href="/02_concepts/long-term.html">长期主义</a> · <a href="/02_concepts/circle-of-competence.html">能力圈</a> · <a href="/02_concepts/contrarian.html">逆向思维</a> · <a href="/02_concepts/reputation.html">声誉</a> · <a href="/02_concepts/risk.html">风险</a></p><p><strong>商业逻辑：</strong> <a href="/02_concepts/insurance-float.html">保险浮存金</a> · <a href="/02_concepts/capital-allocation.html">资本配置</a> · <a href="/02_concepts/share-buybacks.html">股票回购</a></p><p><strong>治理智慧：</strong> <a href="/02_concepts/management.html">管理层</a> · <a href="/02_concepts/corporate-governance.html">董事会治理</a> · <a href="/02_concepts/executive-compensation.html">高管薪酬</a> · <a href="/02_concepts/accounting-earnings.html">GAAP与真实盈利</a></p>',14)])])}const p=a(c,[["render",n]]);export{m as __pageData,p as default};
